package stack

import (
	"sync"
	"testing"
)

func TestPushAndPop(t *testing.T) {
	s := New[int]()
	s.Push(1)
	s.Push(2)
	s.Push(3)
	val, ok := s.Pop()
	if !ok || val != 3 {
		t.Fatalf("expected 3, got %v", val)
	}
	val, ok = s.Pop()
	if !ok || val != 2 {
		t.Fatalf("expected 2, got %v", val)
	}
}

func TestPopEmpty(t *testing.T) {
	s := New[string]()
	_, ok := s.Pop()
	if ok {
		t.Fatal("expected false for empty stack")
	}
}

func TestPeek(t *testing.T) {
	s := New[int]()
	s.Push(42)
	val, ok := s.Peek()
	if !ok || val != 42 {
		t.Fatalf("expected 42, got %v", val)
	}
	// Peek should not remove
	if s.Len() != 1 {
		t.Fatal("peek should not remove element")
	}
}

func TestPeekEmpty(t *testing.T) {
	s := New[int]()
	_, ok := s.Peek()
	if ok {
		t.Fatal("expected false for empty peek")
	}
}

func TestLen(t *testing.T) {
	s := New[int]()
	if s.Len() != 0 {
		t.Fatal("expected 0")
	}
	s.Push(1)
	s.Push(2)
	if s.Len() != 2 {
		t.Fatal("expected 2")
	}
	s.Pop()
	if s.Len() != 1 {
		t.Fatal("expected 1")
	}
}

func TestConcurrentPush(t *testing.T) {
	s := New[int]()
	var wg sync.WaitGroup
	for i := 0; i < 100; i++ {
		wg.Add(1)
		go func(n int) {
			defer wg.Done()
			s.Push(n)
		}(i)
	}
	wg.Wait()
	if s.Len() != 100 {
		t.Fatalf("expected 100 items, got %d", s.Len())
	}
}
